tasks:
{"tasks":"{
	// See https://go.microsoft.com/fwlink/?LinkId=733558
	// for the documentation about the tasks.json format
	"version": "2.0.0",
	"tasks": [
		{
			"label": "Host server (PHP)",
			"detail": "Start a PHP server on the selected path",
			"type": "shell",
			"command": "php",
			"args": [
				"-S",
				"localhost:${input:port}",
				"-t",
				"${input:sourceDirectory}"
			],
			"runOptions": {
				"instanceLimit": 1
			},
			"presentation": {
				"echo": true,
				"reveal": "silent",
				"focus": false,
				"panel": "dedicated",
				"showReuseMessage": false,
				"clear": true
			},
			"problemMatcher": []
		},
		{
			"label": "Compile CSS",
			"type": "shell",
			"command": "npx",
			"args": [
				"tailwindcss",
				"-i",
				"${input:sourceDirectory}/styles/template.css",
				"-o",
				"${input:sourceDirectory}/styles/output.css",
				"-w"
			],
			"detail": "Compile Tailwind CSS template to output file continuously",
			"presentation": {
				"echo": false,
				"reveal": "silent",
				"focus": false,
				"panel": "dedicated",
				"showReuseMessage": false,
				"clear": true
			},
			"problemMatcher": []
		},
		{
			"label": "Compile Handlebars",
			"type": "shell",
			"command": "handlebars",
			"args": [
				"src/templates",
				"--output",
				"src/scripts/templates.js",
				"--min",
				"--known"
			],
			"detail": "Compile minimized Handlebars templates to output file",
			"presentation": {
				"echo": false,
				"reveal": "never",
				"focus": false,
				"panel": "dedicated",
				"showReuseMessage": false,
				"clear": true
			},
			"problemMatcher": []
		}
	],
	"inputs": [
		{
			"id": "sourceDirectory",
			"type": "promptString",
			"description": "Source directory",
			"default": "src"
		},
		{
			"id": "port",
			"type": "promptString",
			"description": "Port to use",
			"default": "8000"
		}
	]
}
"}
